netlist:
* 5-Transistor OTA -- single-stage, PMOS mirror load
.include 'sky130.lib.spice'

.param Wn=4u  Ln=0.5u
.param Wp=8u  Lp=0.5u
.param Wt=10u Lt=1u
.param Ib=20u

* NMOS differential input pair
M1 n1   inp tail 0 nfet W={Wn} L={Ln}
M2 out  inn tail 0 nfet W={Wn} L={Ln}
* PMOS current-mirror active load
M3 n1   n1  vdd vdd pfet W={Wp} L={Lp}
M4 out  n1  vdd vdd pfet W={Wp} L={Lp}
* NMOS tail current source + bias mirror
M5 tail vb  0 0 nfet W={Wt} L={Lt}
Mb  vb   vb  0 0 nfet W={Wt} L={Lt}
Ibias vdd vb {Ib}
* supplies / stimulus
Vdd vdd 0 1.8
Vcm inp 0 0.9
Vin inn inp 0 AC 1
.ac dec 20 1 1G
.end
